                            <span className={`ml-2 px-3 py-1 rounded-full text-xs font-semibold ${
                                isDarkMode 
                                    ? 'bg-purple-900/50 text-purple-300 border border-purple-700/50' 
                                    : 'bg-purple-100 text-purple-600 border border-purple-200'
                            }`}>
                                <svg className="w-3 h-3 mr-1.5 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                                </svg>
                                {t('applicationManagement.table.pagination.filtered') || 'Filtered'}
                            </span>
                        )}
                    </div>
                    <div className="flex items-center space-x-3">
                        <button 
                            className={`group px-4 py-2 border rounded-2xl text-sm font-semibold transition-all duration-300 ${
                                applicationCurrentPage === 1
                                    ? `opacity-50 cursor-not-allowed ${
                                        isDarkMode 
                                            ? 'border-gray-600/50 text-gray-500 bg-gray-800/50' 
                                            : 'border-gray-200/50 text-gray-400 bg-white/50'
                                    }`
                                    : `hover:scale-105 shadow-lg ${
                                        isDarkMode 
                                            ? 'border-gray-600/50 text-gray-200 bg-gray-800/50 hover:bg-gray-700/50' 
                                            : 'border-gray-200/50 text-gray-700 bg-white/50 hover:bg-gray-50/50'
                                    }`
                            }`}
                            onClick={handleApplicationPreviousPage}
                            disabled={applicationCurrentPage === 1}
                        >
                            <span className="flex items-center space-x-2">
                                <svg className="w-4 h-4 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
                                </svg>
                                <span>{t('applicationManagement.table.pagination.previous') || 'Previous'}</span>
                            </span>
                        </button>
                        
                        <div className="flex space-x-2">
                            {[...Array(getApplicationTotalPages())].map((_, index) => {
                                const pageNumber = index + 1;
                                
                                // Show first page, last page, current page, and pages around current page
                                if (getApplicationTotalPages() <= 5 || 
                                    pageNumber === 1 || 
                                    pageNumber === getApplicationTotalPages() || 
                                    (pageNumber >= applicationCurrentPage - 1 && pageNumber <= applicationCurrentPage + 1)) {
                                    return (
                                        <button
                                            key={pageNumber}
                                            className={`px-4 py-2 rounded-2xl text-sm font-semibold transition-all duration-300 shadow-lg ${
                                                applicationCurrentPage === pageNumber
                                                    ? `text-white transform scale-110 ${
                                                        isDarkMode 
                                                            ? 'bg-gradient-to-r from-purple-600 to-pink-600 shadow-purple-500/25' 
                                                            : 'bg-gradient-to-r from-purple-600 to-pink-600 shadow-purple-500/25'
                                                    }`
                                                    : `hover:scale-105 ${
                                                        isDarkMode 
                                                            ? 'border border-gray-600/50 text-gray-200 bg-gray-800/50 hover:bg-gray-700/50' 
                                                            : 'border border-gray-200/50 text-gray-700 bg-white/50 hover:bg-gray-50/50'
                                                    }`
                                            }`}
                                            onClick={() => handleApplicationPageChange(pageNumber)}
                                        >
                                            {pageNumber}
                                        </button>
                                    );
                                } else if (pageNumber === applicationCurrentPage - 2 || pageNumber === applicationCurrentPage + 2) {
                                    return (
                                        <span key={pageNumber} className={`px-3 py-2 ${
                                            isDarkMode ? 'text-gray-500' : 'text-gray-400'
                                        } font-bold`}>
                                            ...
                                        </span>
                                    );
                                }
                                return null;
                            })}
                        </div>
                        
                        <button 
                            className={`group px-4 py-2 border rounded-2xl text-sm font-semibold transition-all duration-300 ${
                                applicationCurrentPage === getApplicationTotalPages()
                                    ? `opacity-50 cursor-not-allowed ${
                                        isDarkMode 
                                            ? 'border-gray-600/50 text-gray-500 bg-gray-800/50' 
                                            : 'border-gray-200/50 text-gray-400 bg-white/50'
                                    }`
                                    : `hover:scale-105 shadow-lg ${
                                        isDarkMode 
                                            ? 'border-gray-600/50 text-gray-200 bg-gray-800/50 hover:bg-gray-700/50' 
                                            : 'border-gray-200/50 text-gray-700 bg-white/50 hover:bg-gray-50/50'
                                    }`
                            }`}
                            onClick={handleApplicationNextPage}
                            disabled={applicationCurrentPage === getApplicationTotalPages()}
                        >
                            <span className="flex items-center space-x-2">
                                <span>{t('applicationManagement.table.pagination.next') || 'Next'}</span>
                                <svg className="w-4 h-4 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                                </svg>
                            </span>
                        </button>
                    </div>
                </div>
            </div>

            {/* View Application Modal */}
            {showViewApplicationModal && selectedApplication && (
                <div className="fixed inset-0 bg-black bg-opacity-50 overflow-y-auto h-full w-full z-50 flex items-center justify-center p-4">
                    <div className={`${
                        isDarkMode 
                            ? 'bg-gray-800 border-gray-700' 
                            : 'bg-white border-gray-200'
                    } rounded-lg shadow-xl border w-full max-w-4xl max-h-[90vh] overflow-y-auto`}>
                        {/* Header */}
                        <div className={`flex items-center justify-between p-6 border-b ${
                            isDarkMode ? 'border-gray-700' : 'border-gray-200'
                        }`}>
                            <div className="flex items-center space-x-3">
                                <div className="w-10 h-10 bg-purple-600 rounded-lg flex items-center justify-center">
                                    <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                                    </svg>
                                </div>
                                <div>
                                    <h3 className={`text-lg font-semibold ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>
                                        {t('applicationManagement.modals.viewApplication.title') || 'Application Details'}
                                    </h3>
                                    <p className={`text-sm ${isDarkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                                        {selectedApplication.firstName} {selectedApplication.lastName}
                                    </p>
                                </div>
                            </div>
                            <button 
                                className={`p-2 rounded-lg transition-colors ${
                                    isDarkMode 
                                        ? 'hover:bg-gray-700 text-gray-400 hover:text-white' 
                                        : 'hover:bg-gray-100 text-gray-500 hover:text-gray-700'
                                }`}
                                onClick={() => {
                                    setShowViewApplicationModal(false);
                                    setSelectedApplication(null);
                                }}
                            >
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                                </svg>
                            </button>
                        </div>
                        
                        {/* Content */}
                        <div className="p-6 space-y-6">
                            {/* Personal Information */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-4">
                                    <h4 className={`text-lg font-semibold ${isDarkMode ? 'text-gray-100' : 'text-gray-900'} border-b ${isDarkMode ? 'border-gray-700' : 'border-gray-200'} pb-2`}>
                                        {t('applicationManagement.sections.personalInfo') || 'Personal Information'}
                                    </h4>
                                    <div className="space-y-3">
                                        <div>
                                            <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                                {t('applicationManagement.fields.fullName') || 'Full Name'}
                                            </label>
                                            <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'}`}>
                                                {selectedApplication.firstName} {selectedApplication.lastName}
                                            </p>
                                        </div>
                                        <div>
                                            <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                                {t('applicationManagement.fields.email') || 'Email'}
                                            </label>
                                            <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'}`}>{selectedApplication.email}</p>
                                        </div>
                                        <div>
                                            <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                                {t('applicationManagement.fields.phone') || 'Phone'}
                                            </label>
                                            <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'}`}>{selectedApplication.phone}</p>
                                        </div>
                                        {selectedApplication.dateOfBirth && (
                                            <div>
                                                <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                                    {t('applicationManagement.fields.dateOfBirth') || 'Date of Birth'}
                                                </label>
                                                <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'}`}>
                                                    {new Date(selectedApplication.dateOfBirth).toLocaleDateString()}
                                                </p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                                
                                <div className="space-y-4">
                                    <h4 className={`text-lg font-semibold ${isDarkMode ? 'text-gray-100' : 'text-gray-900'} border-b ${isDarkMode ? 'border-gray-700' : 'border-gray-200'} pb-2`}>
                                        {t('applicationManagement.sections.academicInfo') || 'Academic Information'}
                                    </h4>
                                    <div className="space-y-3">
                                        <div>
                                            <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                                {t('applicationManagement.fields.program') || 'Program'}
                                            </label>
                                            <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'} font-medium`}>{selectedApplication.program}</p>
                                        </div>
                                        {selectedApplication.educationLevel && (
                                            <div>
                                                <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                                    {t('applicationManagement.fields.educationLevel') || 'Education Level'}
                                                </label>
                                                <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'}`}>{selectedApplication.educationLevel}</p>
                                            </div>
                                        )}
                                        {selectedApplication.startDate && (
                                            <div>
                                                <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                                    {t('applicationManagement.fields.startDate') || 'Start Date'}
                                                </label>
                                                <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'}`}>
                                                    {new Date(selectedApplication.startDate).toLocaleDateString()}
                                                </p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* Additional Information */}
                            {selectedApplication.personalStatement && (
                                <div className="space-y-4">
                                    <h4 className={`text-lg font-semibold ${isDarkMode ? 'text-gray-100' : 'text-gray-900'} border-b ${isDarkMode ? 'border-gray-700' : 'border-gray-200'} pb-2`}>
                                        {t('applicationManagement.fields.personalStatement') || 'Personal Statement'}
                                    </h4>
                                    <div className={`p-4 rounded-lg ${isDarkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                                        <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'} whitespace-pre-wrap`}>
                                            {selectedApplication.personalStatement}
                                        </p>
                                    </div>
                                </div>
                            )}

                            {/* Application Status and Metadata */}
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <div>
                                    <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                        {t('applicationManagement.fields.status') || 'Application Status'}
                                    </label>
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium mt-1 ${
                                        selectedApplication.status === 'approved' ? 'bg-green-100 text-green-800' :
                                        selectedApplication.status === 'rejected' ? 'bg-red-100 text-red-800' :
                                        selectedApplication.status === 'under_review' ? 'bg-blue-100 text-blue-800' :
                                        'bg-yellow-100 text-yellow-800'
                                    }`}>
                                        {selectedApplication.status ? selectedApplication.status.charAt(0).toUpperCase() + selectedApplication.status.slice(1).replace('_', ' ') : 'Pending'}
                                    </span>
                                </div>
                                <div>
                                    <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                        {t('applicationManagement.fields.submittedOn') || 'Submitted On'}
                                    </label>
                                    <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'}`}>
                                        {new Date(selectedApplication.createdAt || Date.now()).toLocaleDateString()}
                                    </p>
                                </div>
                                <div>
                                    <label className={`text-sm font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'}`}>
                                        {t('applicationManagement.fields.applicationId') || 'Application ID'}
                                    </label>
                                    <p className={`${isDarkMode ? 'text-gray-100' : 'text-gray-900'} font-mono text-sm`}>
                                        {selectedApplication._id?.slice(-8) || 'N/A'}
                                    </p>
                                </div>
                            </div>
                        </div>
                        
                        {/* Modal Footer */}
                        <div className={`flex justify-end space-x-3 p-6 border-t ${
                            isDarkMode ? 'border-gray-700' : 'border-gray-200'
                        }`}>
                            <button 
                                onClick={() => handleSendMessage(selectedApplication)}
                                className="inline-flex items-center px-4 py-2 bg-green-600 text-white font-medium rounded-lg hover:bg-green-700 transition-colors"
                            >
                                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 7.89a2 2 0 002.83 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                                </svg>
                                {t('applicationManagement.actions.sendMessage') || 'Send Message'}
                            </button>
                            <button 
                                onClick={() => {
                                    setShowViewApplicationModal(false);
                                    setSelectedApplication(null);
                                }}
                                className={`px-4 py-2 border rounded-lg font-medium transition-colors ${
                                    isDarkMode 
                                        ? 'border-gray-600 text-gray-300 bg-gray-700 hover:bg-gray-600' 
                                        : 'border-gray-300 text-gray-700 bg-white hover:bg-gray-50'
                                }`}
                            >
                                {t('applicationManagement.actions.close') || 'Close'}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Delete Application Confirmation Modal */}
            {showDeleteApplicationConfirm && applicationToDelete && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
                    <div className={`${
                        isDarkMode 
                            ? 'bg-gray-800 border-gray-700' 
                            : 'bg-white border-gray-200'
                    } rounded-lg shadow-xl border w-full max-w-md`}>
                        <div className="p-6">
                            {/* Warning Icon */}
                            <div className="flex justify-center mb-4">
                                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center">
                                    <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L3.732 16.5c-.77.833.192 2.5 1.732 2.5z" />
                                    </svg>
                                </div>
                            </div>
                            
                            {/* Content */}
                            <div className="text-center space-y-3">
                                <h3 className={`text-lg font-semibold ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>
                                    {t('applicationManagement.modals.deleteApplication.title') || 'Delete Application'}
                                </h3>
                                <div className={`text-sm ${isDarkMode ? 'text-gray-300' : 'text-gray-600'} space-y-2`}>
                                    <p>
                                        {t('applicationManagement.modals.deleteApplication.message', { 
                                            name: `${applicationToDelete.firstName} ${applicationToDelete.lastName}`, 
                                            program: applicationToDelete.program 
                                        }) || `Are you sure you want to delete the application from ${applicationToDelete.firstName} ${applicationToDelete.lastName} for ${applicationToDelete.program}?`}
                                    </p>
                                    <div className={`p-3 rounded-lg ${
                                        isDarkMode 
                                            ? 'bg-red-900 bg-opacity-30 border border-red-800' 
                                            : 'bg-red-50 border border-red-200'
                                    }`}>
                                        <p className="text-red-600 font-medium text-sm">
                                            {t('applicationManagement.modals.deleteApplication.warning') || 'This action cannot be undone.'}
                                        </p>
                                    </div>
                                </div>
                            </div>
                            
                            {/* Action Buttons */}
                            <div className="flex justify-center space-x-3 mt-6">
                                <button
                                    onClick={() => {
                                        setShowDeleteApplicationConfirm(false);
                                        setApplicationToDelete(null);
                                    }}
                                    className={`px-4 py-2 border rounded-lg font-medium transition-colors ${
                                        isDarkMode 
                                            ? 'border-gray-600 text-gray-300 bg-gray-700 hover:bg-gray-600' 
                                            : 'border-gray-300 text-gray-700 bg-white hover:bg-gray-50'
                                    }`}
                                >
                                    {t('applicationManagement.actions.cancel') || 'Cancel'}
                                </button>
                                <button
                                    onClick={confirmDeleteApplication}
                                    className="inline-flex items-center px-4 py-2 bg-red-600 text-white font-medium rounded-lg hover:bg-red-700 transition-colors"
                                >
                                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                    </svg>
                                    {t('applicationManagement.actions.confirmDelete') || 'Yes, Delete'}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );

    const renderContactManagement = () => (
        <div className="space-y-8">
            {/* Header */}
            <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
                <div className="space-y-2">
                    <h2 className={`text-2xl font-bold ${isDarkMode ? 'text-gray-100' : 'text-gray-900'} flex items-center transition-colors duration-300`}>
                        <span className="mr-2">📧</span>
                        Contact Management
                    </h2>
                    <div className="flex flex-wrap gap-4 text-sm">
                        <span className={`${isDarkMode ? 'text-gray-400' : 'text-gray-600'} transition-colors duration-300`}>
                            <span className={`font-semibold ${isDarkMode ? 'text-gray-100' : 'text-gray-900'} transition-colors duration-300`}>{contactSubmissions.length}</span> Total Messages
                        </span>
                        <span className={`${isDarkMode ? 'text-gray-400' : 'text-gray-600'} transition-colors duration-300`}>
                            <span className="font-semibold text-orange-600">{contactSubmissions.filter(contact => contact.status === 'pending').length}</span> Pending
                        </span>
                        <span className={`${isDarkMode ? 'text-gray-400' : 'text-gray-600'} transition-colors duration-300`}>
                            <span className="font-semibold text-green-600">{contactSubmissions.filter(contact => contact.status === 'resolved').length}</span> Resolved
                        </span>
                        <span className={`${isDarkMode ? 'text-gray-400' : 'text-gray-600'} transition-colors duration-300`}>
                            <span className="font-semibold text-blue-600">{contactSubmissions.filter(contact => contact.status === 'approved').length}</span> Priority
                        </span>
                    </div>
                </div>
                
                <div className="flex flex-col sm:flex-row gap-3">
                    <div className="flex flex-col sm:flex-row gap-2">
                        <input 
                            type="text" 
                            placeholder="🔍 Search messages..." 
                            value={searchTermContact}
                            onChange={(e) => setSearchTermContact(e.target.value)}
                            className={`px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                                isDarkMode 
                                    ? 'border-gray-600 bg-gray-800 text-gray-100 placeholder-gray-400' 
                                    : 'border-gray-300 bg-white text-gray-900'
                            }`}
                        />
                        <select 
                            value={selectedCategory} 
                            onChange={(e) => setSelectedCategory(e.target.value)}
                            className={`px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                                isDarkMode 
                                    ? 'border-gray-600 bg-gray-800 text-gray-100' 
                                    : 'border-gray-300 bg-white text-gray-900'
                            }`}
                        >
                            <option value="">All Categories</option>
                            <option value="general">General</option>
                            <option value="admissions">Admission</option>
                            <option value="courses">Course Information</option>
                            <option value="careers">Career Services</option>
                            <option value="others">Others</option>
                        </select>
                        <select 
                            value={selectedContactStatus}
                            onChange={(e) => setSelectedContactStatus(e.target.value)}
                            className={`px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                                isDarkMode 
                                    ? 'border-gray-600 bg-gray-800 text-gray-100' 
                                    : 'border-gray-300 bg-white text-gray-900'
                            }`}
                        >
                            <option value="">All Status</option>
                            <option value="pending">Pending</option>
                            <option value="approved">Priority</option>
                            <option value="resolved">Resolved</option>
                            <option value="ignored">Ignored</option>
                        </select>
                    </div>
                    <button className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-lg text-white bg-blue-600 hover:bg-blue-700 transition-colors">
                        📤 Export Messages
                    </button>
                </div>
            </div>
    
            {/* Contact Messages Table - Dark Mode */}
            <div className={`${isDarkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-100'} rounded-2xl shadow-xl border overflow-hidden transition-colors duration-300`}>
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                        <thead className={`${isDarkMode ? 'bg-gradient-to-r from-gray-800 to-gray-700' : 'bg-gradient-to-r from-gray-50 to-gray-100'} transition-colors duration-300`}>
                            <tr>
                                <th className={`px-6 py-4 text-left text-xs font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'} uppercase tracking-wider transition-colors duration-300`}>
                                    <div className="flex items-center space-x-1">
                                        <span>👤 Contact</span>
                                        <span className={`${isDarkMode ? 'text-gray-500' : 'text-gray-400'} transition-colors duration-300`}>↕️</span>
                                    </div>
                                </th>
                                <th className={`px-6 py-4 text-left text-xs font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-500'} uppercase tracking-wider transition-colors duration-300`}>
                                    <div className="flex items-center space-x-1">
                                        <span>📧 Details</span>
                                        <span className={`${isDarkMode ? 'text-gray-500' : 'text-gray-400'} transition-colors duration-300`}>↕️</span>
                                    </div>
                                </th>
